  ('elementary-10ced7e2-moex-00911', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '「如膠似漆」與「水乳交融」語意對應關係，與下列何組最不相同？', '["「宵衣旰食」與「廢寢忘餐」", "「推心置腹」與「披肝瀝膽」", "「弊絕風清」與「政以賄成」", "「巾幗鬚眉」與「女中豪傑」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00912', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '「素養跟知識有沒有差別？當然有，而且有著極其關鍵的差別。我們不要忘記，納粹頭子很多會彈鋼琴、有 哲學博士學位。」下列選項，最接近意旨的是：', '["知識易使人傲慢", "讀書越多，精神就越健康而勇敢", "才能只是天分，善良卻是一種選擇", "不要用華麗外衣裝飾，而是以知識武裝自己"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00913', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '下列選項，何者表達出「壯志猶存」的懷抱？', '["人生得意須盡歡，莫使金樽空對月", "今朝有酒今朝醉，明日愁來明日愁", "人生到處知何似，應似飛鴻踏雪泥", "夜闌臥聽風吹雨，鐵馬冰河入夢來"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00914', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '在公文中稱受文者為「鈞部」，可知發文者為：', '["有隸屬關係的上級機關", "有隸屬關係的下級機關", "無隸屬關係的上級機關", "無隸屬關係的下級機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00915', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '有關公文稱謂用語，下列正確的選項是：', '["大學發函給校友，自稱本校，稱對方為臺端", "教育部發函各大學，自稱鈞部，稱對方為貴校", "小華旅日請外交部提供協助，自稱本人，稱對方為大部", "臺中市中小學發函給臺中市政府教育局，自稱職，稱對方為鈞府"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00916', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '各機關就主管業務，向公眾或特定之對象宣布周知時，應使用何種公文？', '["令", "函", "呈", "公告"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00917', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '下列題辭，最適合用於祝賀「演唱比賽冠軍」的選項是：', '["妙語如珠", "金聲玉振", "弦歌不輟", "響遏行雲 玉潤珠圓"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00918', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '下列「」中有關顏色的詞語，解釋正確的選項是：', '["他在家的門口上「張貼紅榜」：指獲得榮譽", "他無處謀生，打算「投入綠林」：指隱居不仕", "眼前美景就像「明日黃花」，千萬要把握：指花團錦簇", "對於「懷黃佩紫」的人來說，名譽勝於一切：指達官顯貴 「陽春白雪」的人，總是人群中的少數：絕美景色"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00919', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '下列常用成語「」內的字，解釋正確的選項是：', '["甘之如「飴」：甜餅", "室如懸「磬」：石鼓", "揚「湯」止沸：熱水", "感激「涕」零：眼淚 短「兵」相接：士兵"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00920', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '張貼理髮店大門的對聯，下列選項正確的是：', '["雖云毫末技藝，卻是頂上功夫", "現出廬山真面目，留住秋水舊丰神", "創人間頭等事業，理世上不平東西", "雖無劉阮逢仙術，只效岐黃救世心 技術革新頭頭是道，容光煥發面面皆春"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
